<script>
// Scroll reveal
const obs=new IntersectionObserver(entries=>{
  entries.forEach(e=>{if(e.isIntersecting){e.target.classList.add('on');obs.unobserve(e.target)}});
},{threshold:0.1});
document.querySelectorAll('.rev,.rev-l,.rev-r').forEach(el=>obs.observe(el));

// Counters
const cObs=new IntersectionObserver(entries=>{
  entries.forEach(e=>{
    if(!e.isIntersecting)return;
    const el=e.target,t=parseInt(el.dataset.target);
    if(!t)return;
    let n=0;
    const go=()=>{n+=Math.ceil(t/50);if(n>=t){el.textContent=t;return;}el.textContent=n;requestAnimationFrame(go);};
    go();cObs.unobserve(el);
  });
},{threshold:0.5});
document.querySelectorAll('.stat-n[data-target]').forEach(el=>cObs.observe(el));

// Skill bars
const sObs=new IntersectionObserver(entries=>{
  entries.forEach(e=>{
    if(!e.isIntersecting)return;
    e.target.querySelectorAll('.skill-fill2').forEach(f=>{
      setTimeout(()=>{f.style.width=f.dataset.w+'%'},200);
    });
    sObs.unobserve(e.target);
  });
},{threshold:0.2});
document.querySelectorAll('#skills .container').forEach(el=>sObs.observe(el));
</script>
